const body = $input.first().json;

// Slack URL verification challenge
if (body.type === 'url_verification') {
  return [{ json: { challenge: body.challenge, skip: true } }];
}

// Extract message from Slack event
const event = body.event;
if (!event || event.type !== 'message' || event.subtype) {
  return [{ json: { skip: true } }];
}

const text = event.text || '';

// Only process [FIRING] messages
if (!text.startsWith('[FIRING')) {
  return [{ json: { skip: true } }];
}

// Parse alert fields
const lines = text.split('\n').map(l => l.trim());

// Extract alertname from first line: [FIRING:1] AlertName ...
const firstLine = lines[0];
const alertNameMatch = firstLine.match(/\[FIRING[^\]]*\]\s+(\S+)/);
const alertName = alertNameMatch ? alertNameMatch[1] : 'Unknown';

// Extract severity
const severityMatch = text.match(/severity[:\s•]+([\w]+)/);
const severity = severityMatch ? severityMatch[1] : 'unknown';

// Extract service/app name
let appName = '';
const serviceMatch = text.match(/Service:\s*([\w-]+)/);
const destAppMatch = text.match(/destination_app[:\s•]+([\w-]+)/);
const containerMatch = text.match(/container[:\s•]+([\w-]+)/);
appName = serviceMatch?.[1] || destAppMatch?.[1] || containerMatch?.[1] || '';

// Extract namespace from message or derive from appName
let namespace = '';
const nsMatch = text.match(/namespace[:\s•]+([\w-]+)/);
if (nsMatch) {
  namespace = nsMatch[1];
} else if (appName) {
  // Naming rule: prd-mall-backoffice -> prd-mall
  const parts = appName.split('-');
  namespace = parts.length >= 2 ? parts[0] + '-' + parts[1] : appName;
}

// Extract pod name
const podMatch = text.match(/pod[:\s•]+([\w-\/]+)/);
const pod = podMatch ? podMatch[1].split('/').pop() : '';

// Extract timestamp (use current time if not found)
const alertTimestamp = Math.floor(Date.now() / 1000);
const startTime = alertTimestamp - 600; // -10 min
const endTime = alertTimestamp + 600;   // +10 min

// Classify alert type
const infraAlerts = ['OomKiller', 'CrashLoop', 'NodeNotReady', 'PodNotReady', 'DiskPressure', 'MemoryPressure'];
const isInfraAlert = infraAlerts.some(k => alertName.toLowerCase().includes(k.toLowerCase()));
const alertType = isInfraAlert ? 'infra' : 'service';

return [{
  json: {
    skip: false,
    raw: text,
    channel: event.channel,
    ts: event.ts,
    alertName,
    alertType,
    appName,
    namespace,
    pod,
    severity,
    startTime: String(startTime * 1e9), // nanoseconds for Loki
    endTime: String(endTime * 1e9),
    startTimeMs: startTime,
    endTimeMs: endTime,
  }
}];
